#include <bits/stdc++.h>
using namespace std;
#define ll long long
const int N=200005;
vector<int> g[N],col[N];
int n,k,c[N],cnt[N],dp[N],dep[N],vis[N],mx,mxnum,ans=0x3f3f3f3f,vis2[N],Vis[N],Cnt,fa[N];//vis2 :这个颜色有没有放进queue里 
void dfs(int u,int f)//求连通块的根 
{
	fa[u]=f;
	Vis[u]=Cnt;
	vis2[c[u]]=0;
	dep[u]=dep[f]+1;
	if(dep[u]>mx)
	{
		mx=dep[u];
		mxnum=u;
	}
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(v==f||vis[v]) continue;
		dfs(v,u);
	}
}
void fun(int u)
{
	queue<int> q;
	q.push(c[u]);
	int cntt=0;
	vis2[c[u]]=1;
	while(!q.empty())
	{
		int tmp=q.front();
		q.pop();
		for(int i=0;i<col[tmp].size();i++)
		{
			int v=col[tmp][i];
			if(Vis[v]!=Cnt)
			{
				return ;
			}
			while(dep[v])
			{
				if(vis2[c[v]]==0)
				{
					vis2[c[v]]=1;
					q.push(c[v]);
					cntt++;
				}
				dep[v]=0;
				v=fa[v];
			}
		}
	}
	ans=min(ans,cntt);
}
int getroot(int u,int f)//求连通块的根 
{
	Cnt++;
	mx=0;
	dfs(u,0);
	mx=0;
	dfs(mxnum,0);
	return mxnum;
}
void solve(int u)//点分治 
{
	fun(u);
	vis[u]=1;
	for(int i=0;i<g[u].size();i++)
	{
		int v=g[u][i];
		if(vis[v]) continue;
		int root=getroot(v,0);
		solve(root);
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>k;
	for(int i=1;i<n;i++)
	{
		int u,v;
		cin>>u>>v;
		g[u].push_back(v);
		g[v].push_back(u);
	}
	for(int i=1;i<=n;i++)
	{
		cin>>c[i];
	}
	solve(getroot(1,0));
	cout<<ans;
	return 0;
}
